code = """import json, pandas as pd

# load books (may be in file)
books_src = var_call_U6bgpNWDnPwVoRn40elcBmyv
if isinstance(books_src, str):
    with open(books_src, 'r', encoding='utf-8') as f:
        books = json.load(f)
else:
    books = books_src

reviews = var_call_prxE4mi7zboPw4R0pgfkAq7J

df_books = pd.DataFrame(books)
df_rev = pd.DataFrame(reviews)

# parse ids like bookid_12 vs purchaseid_12
for col in ['book_id']:
    df_books[col] = df_books[col].astype(str)
df_rev['purchase_id'] = df_rev['purchase_id'].astype(str)

def id_suffix(x):
    # take trailing digits
    import re
    m = re.search(r'(\d+)\s*$', x)
    return m.group(1) if m else None

df_books['id_num'] = df_books['book_id'].map(id_suffix)
df_rev['id_num'] = df_rev['purchase_id'].map(id_suffix)

# english-language filter from details string
# assume contains 'written in English' or 'available in English' or 'Language' etc.
df_books['is_english'] = df_books['details'].fillna('').str.contains('English', case=False, regex=False)

# join
merged = df_books.merge(df_rev, on='id_num', how='inner', suffixes=('_book','_rev'))
merged['avg_rating'] = merged['avg_rating'].astype(float)
merged['review_count'] = merged['review_count'].astype(int)

out = merged[(merged['avg_rating'] == 5.0) & (merged['is_english'])][['title','subtitle','author','book_id','avg_rating','review_count']].sort_values(['title','book_id'])

result = out.to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(result, ensure_ascii=False))"""

